def max_sum_digits(n):
    n = str(n)
    if len(n) == 1:
        return int(n)
    if '9' * len(n) <= n:
        return int('9' * len(n))
    for i in range(len(n)):
        if n[i] != '9':
            return int(n[:i] + str(int(n[i]) - 1) + '9' * (len(n) - i - 1))

n = int(input().strip())
print(max_sum_digits(n))

