import java.util.Scanner;

public class Polycarp {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int T = scanner.nextInt();
        for (int t = 1; t <= T; t++) {
            int n = scanner.nextInt();
            int[] plays = new int[n];
            int[] clears = new int[n];
            for (int i = 0; i < n; i++) {
                plays[i] = scanner.nextInt();
                clears[i] = scanner.nextInt();
            }
            boolean correct = true;
            for (int i = 0; i < n; i++) {
                if (plays[i] != polycarp(plays, clears, i)) {
                    correct = false;
                    break;
                }
            }
            if (correct) {
                System.out.println("YES");
            } else {
                System.out.println("NO");
            }
        }
    }
    static int polycarp(int[] plays, int[] clears, int moment) {
        int maxPlays = 0;
        int maxClears = 0;
        for (int i = 0; i < moment; i++) {
            if (plays[i] > maxPlays) {
                maxPlays = plays[i];
            }
            if (clears[i] > maxClears) {
                maxClears = clears[i];
            }
        }
        return maxPlays + maxClears;
    }
}

def max_permutation(a, b):
    a = list(str(a))
    b = list(str(b))
    for i in range(len(a)):
        for j in range(i+1, len(a)):
            if a[i] < a[j]:
                a[i], a[j] = a[j], a[i]
                if int(''.join(a)) <= b:
                    return int(''.join(a))
                a[i], a[j] = a[j], a[i]
    return int(''.join(a))

a = int(input())
b = int(input())
print(max_permutation(a, b))

n, k = map(int, input().split())

if k > n*(n-1)//2:
    print("-1")
else:
    matrix = [[0]*n for _ in range(n)]
    count = 0
    for i in range(n):
        for j in range(i+1):
            if count < k:
                matrix[i][j] = 1
                count += 1
    for i in range(n-1, -1, -1):
        for j in range(n-1, i, -1):
            if count < k:
                matrix[i][j] = 1
                count += 1
    for i in range(n):
        print(" ".join(map(str, matrix[i]))

import math

def comb(n, r):
 return math.gcd(math.factorial(n) // (math.factorial(r) * math.factorial(n-r)), 1000000003)

