n = int(input())
a = list(map(int, input().split()))
dp = [[[0]*305 for _ in range(305)] for _ in range(305)]
dp[0][0][0] = 1
for i in range(301):
    for j in range(301):
        for k in range(301):
            if dp[i][j][k] == 0:
                continue
            for x in range(1, 301):
                if i+x < 301:
                    dp[i+x][j][k] = max(dp[i+x][j][k], 1-dp[i][j][k])
                if j+x < 301:
                    dp[i][j+x][k] = max(dp[i][j+x][k], 1-dp[i][j][k])
                if k+x < 301:
                    dp[i][j][k+x] = max(dp[i][j][k+x], 1-dp[i][j][k])
                if i+x < 301 and j+x < 301 and k+x < 301:
                    dp[i+x][j+x][k+x] = max(dp[i+x][j+x][k+x], 1-dp[i][j][k])
if n == 1:
    if dp[a[0]][0][0] == 1:
        print("BitLGM")
    else:
        print("BitAryo")
elif n == 2:
    if dp[a[0]][a[1]][0] == 1:
        print("BitLGM")
    else:
        print("BitAryo")
else:
    if dp[a[0]][a[1]][a[2]] == 1:
        print("BitLGM")
    else:
        print("BitAryo")

from math import gcd

def is_valid(deck, k):
    product = 1
    for card in deck:
        product *= card
    return product % k == 0

def count_valid_decks(n, k, cards):
    count = 0
    for x in range(n):
        for y in range(n - x):
            if x + y < n:
                deck = cards[x:n-y]
                if is_valid(deck, k):
                    count += 1
    return count

# Read input
n, k = map(int, input().split())
cards = list(map(int, input().split()))

# Solve the problem
print(count_valid_decks(n, k, cards))

