def is_same_configuration(puzzle1, puzzle2):
    return puzzle1 == puzzle2

def slide_tile(puzzle, tile):
    row, col = ord(tile) - ord('A') + 1, int(col / 2) + 1 if col.isdigit() else col
    return [list(line)[::] for line in [
        [c if i != row or (i == row and j != col) else (
            line[j] if j != col else tile
        ) for i, c in enumerate(line)] for line in puzzles
    ]

def bffl(puzzles):
    puzzles = [list(map(str, line.strip().split())) for line in input().strip().split('\n')[2:]]
    for i in range(len(puzzles)):
        puzzles[i] = [list(line) for line in puzzles[i]]

    while set(puzzles) != {puzzles[0]: None}:
        puzzle1, puzzle2 = puzzles[0], puzzles[1]
        for move in ['AA', 'AB', 'BA', 'BB']:
            puzzle1 = slide_tile(puzzle1, move[0])
            puzzle2 = slide_tile(puzzle2, move[1])
            if is_same_configuration(puzzle1, puzzle2):
                return print('YES')
                exit()

    print('NO')

