def find_kth_smallest_divisor(n, k):
    divisors = set()
    for i in range(1, int(n**0.5) + 1):
        if n % i == 0:
            divisors.add(i)
            if i != n // i:
                divisors.add(n // i)

    if len(divisors) < k:
        return -1
    else:
        return sorted(divisors)[k - 1]

# Read input
