# Find and print the kth smallest divisor
print(find_kth_smallest_divisor(n, k))

import math

n, k = map(int, input().split())


def divisors(n):
    divisors = []
    for i in range(1, int(math.sqrt(n)) + 1):
        if n % i == 0:
            divisors.append(i)
            if i != n // i:
                divisors.append(n // i)
    return divisors


def kth_smallest(n, k):
    divisors = divisors(n)
    divisors.sort()
    if k > len(divisors):
        return -1
    return divisors[k - 1]


print(kth_smallest(n, k))

