def max_weight_subset(W, items):
    dp = [0] * (W + 1)
    for i in range(1, 9):
        for j in range(W, -1, -1):
            for k in range(min(items[i-1], j//i) + 1):
                dp[j] = max(dp[j], dp[j - k*i] + k*i)

    return dp[W]

