from math import gcd

def is_coprime(a, b):
    return gcd(a, b) == 1

def find_coprime_array(n, arr):
    result = arr.copy()
    for i in range(1, n):
        if not is_coprime(result[i-1], result[i]):
            for j in range(1, 10**9+1):
                if is_coprime(result[i-1], j) and is_coprime(result[i], j):
                    result.insert(i, j)
                    break
    return len(result) - n, result

