def solve():
    x0, y0, ax, ay, bx, by = map(int, input().split())
    xs, ys, t = map(int, input().split())
    x = [x0]
    y = [y0]
    while True:
        x.append(ax*x[-1]+bx)
        y.append(ay*y[-1]+by)
        if x[-1] > 2e16 or y[-1] > 2e16:
            break
    n = len(x)
    ans = 0
    for i in range(n):
        for j in range(i, n):
            dist = abs(x[j]-x[i]) + abs(y[j]-y[i])
            extra = min(abs(x[i]-xs)+abs(y[i]-ys), abs(x[j]-xs)+abs(y[j]-ys))
            if dist + extra <= t:
                ans = max(ans, j-i+1)
    print(ans)

solve()

import math

def sign(x, y):
 return (x >= 0 and y >= 0) or (x < 0 and y > 0)

def area(x1, y1, r1, x2, y2, r2):
 return math.pi * ((r1 + r2) ** 2 - (r1 - r2) ** 2) / 2

def check_intersect(x1, y1, r1, x2, y2, r2):
 return abs(x1 - x2) ** 2 + abs(y1 - y2) ** 2 <= (r1 + r2) ** 2

n = int(input())
