def in_circle(x, y, circles):
 count = 0
 for circle in circles:
 if abs(x - circle[0]) <= circle[2] and abs(y - circle[1]) <= circle[2]:
 count += 1
 return count > 0

def count_regions(circles):
 regions = 0
 stack = [(0, 0, 1)]
 while stack:
 x, y, direction = stack
 if not in_circle(x, y, circles):
 if sign(x, y) == 1:
 regions += 1
 else:
 regions -= 1
 for dx, dy in [(1, 0), (-1, 0), (0, 1), (0, -1)]:
 nx, ny = x + dx, y + dy
 if 0 <= nx <= 10 and 0 <= ny <= 10 and not in_circle(nx, ny, circles):
 stack.append((nx, ny, -direction))
 return regions + 1

print(count_regions(circles))

