n, x, y = map(int, input().split())
s = input()

# dp[i][j] represents the minimum cost to convert s[0:i+1] to all 1s
dp = [[0] * (n + 1) for _ in range(n + 1)]

# base case
for i in range(n + 1):
    dp[i][i] = i * y if s[i - 1] == '0' else i * x

# compute the minimum cost for each length of substrings
for i in range(2, n + 1):
    for j in range(i, n + 1):
        # choose the two operations
        if s[j - 1] == '0':
            dp[i][j] = min(dp[i][j - 1] + y, dp[i - 1][j] + x)
        else:
            dp[i][j] = min(dp[i][j - 1] + y, dp[i - 1][j] + x)

        # if the whole string is 1, then the cost is 0
        if dp[1][j] == 0:
            return 0

# print the minimum cost
print(dp[n][n])

