import math
n = int(input())
if n == 1:
print(1)
else:
if n % 2 == 0:
print(n * (n - 1) * (n - 2))
else:
print(n * (n - 1) * (n - 3))

def solve(n):
    if n == 1:
        return 1
    elif n == 2:
        return 2
    elif n == 3:
        return 6
    elif n % 2 == 1:
        return n * (n - 1) * (n - 2)
    elif n % 3 != 0:
        return n * (n - 1) * (n - 3)
    else:
        return (n - 1) * (n - 2) * (n - 3)

n = int(input().strip())
print(solve(n))

