def min_operations(x, y, m):
    if x >= m or y >= m:
        return 0

    if x <= 0 and y <= 0:
        return -1

    if x < y:
        x, y = y, x

    operations = 0
    while y < m:
        y, x = x + y, y
        operations += 1

    return operations

# Read input
