def is_mirror(word):
    mirror_letters = {'A': 'A', 'H': 'H', 'I': 'I', 'M': 'M', 'O': 'O', 'T': 'T', 'U': 'U', 'V': 'V', 'W': 'W', 'X': 'X', 'Y': 'Y', '1': '1', '8': '8', '0': '0', '2': 'S', 'S': '2', '5': '5', '3': 'E', 'E': '3', '6': '9', '9': '6'}
    word = word.upper()
    return all(letter in mirror_letters and mirror_letters[letter] == word[::-1][i] for i, letter in enumerate(word))

word = input()
print('YES' if is_mirror(word) else 'NO')

