import java.util.Scanner;

public class Solution {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int n = scanner.nextInt();
        int m = scanner.nextInt();

        // Check if the given graph is possible
        boolean isPossible = true;
        for (int i = 0; i < m; i++) {
            int u = scanner.nextInt();
            int v = scanner.nextInt();
            if (u == v) continue; // Ignore self-edges
            if (u < v && v - u == 1) { // Check for adjacent letters
                isPossible = false;
                break;
            }
        }
        if (isPossible) {
            // Find the possible string
            String s = "";
            for (int i = 0; i < n; i++) {
                char c = 'a' + (i % 3);
                s += c;
            }
            System.out.println("Yes");
            System.out.println(s);
        } else {
            System.out.println("No");
        }
    }
}

def hanoi_cost(t, n, start, end, aux):
    if n == 1:
        return t[start][end]
    else:
        return hanoi_cost(t, n-1, start, aux, end) + t[start][end] + hanoi_cost(t, n-1, aux, end, start)

