def min_ impassable_cells(n, m, island):
    # Create a 2D array to store the forest status
    forest = [[False for _ in range(m)] for _ in range(n)]

    # Initialize the forest status for the starting cell
    forest[0][0] = True

    # Fill in the rest of the forest status
    for i in range(1, n):
        for j in range(1, m):
            # If the current cell is forest, it's already impassable
            if island[i-1][j-1] == "#":
                forest[i][j] = True
            # If the current cell is not forest and the cell below it is forest, it's impassable
            elif forest[i-1][j] and forest[i][j-1]:
                forest[i][j] = True
            # If the current cell is not forest and there's no cell below it that's forest, it's passable
            elif not forest[i-1][j] and not forest[i][j-1]:
                forest[i][j] = False

    # Count the number of impassable cells
    count = 0
    for i in range(n):
        for j in range(m):
            if forest[i][j]:
                count += 1

    return count

# Example usage
n, m = map(int, input().split())
island = [list(input()) for _ in range(n)]
print(min_ impassable_cells(n, m, island))

