            neighbours.append((x, y + 1))
        if field[x][y + 1] == "*":
            neighbours.append((x, y + 1))
    for neighbour in neighbours:
        if field[neighbour[0]][neighbour[1]] == "P":
            neighbours.remove(neighbour)
    return neighbours


