    neighbours = []
    if x > 0:
        if field[x - 1][y] == "P":
            neighbours.append((x - 1, y))
        if field[x - 1][y] == "*":
            neighbours.append((x - 1, y))
    if x < n - 1:
        if field[x + 1][y] == "P":
            neighbours.append((x + 1, y))
        if field[x + 1][y] == "*":
            neighbours.append((x + 1, y))
    if y > 0:
        if field[x][y - 1] == "P":
            neighbours.append((x, y - 1))
        if field[x][y - 1] == "*":
            neighbours.append((x, y - 1))
    if y < n - 1:
        if field[x][y + 1] == "P":
            neighbours.append((x, y + 1))
        if field[x][y + 1] == "*":
            neighbours.append((x, y + 1))
    for neighbour in neighbours:
