from itertools import permutations

def average_guests(n, sizes, p):
    total_guests = 0
    for order in permutations(sizes):
        current_size = 0
        guests_in = 0
        for size in order:
            if current_size + size <= p:
                current_size += size
                guests_in += 1
            else:
                break
        total_guests += guests_in
    return total_guests / (n * factorial(n))

def factorial(n):
    if n == 0 or n == 1:
        return 1
    else:
        return n * factorial(n-1)

