def fix_time(time_format, time):
    hours, minutes = map(int, time.split(':'))

    if time_format == 12:
        if hours == 0:
            hours = 1
        elif hours > 12:
            if hours % 10 != 0:
                hours = hours % 10
            else:
                hours = 10
    else:
        if hours >= 24:
            hours = hours % 10

    if minutes >= 60:
        minutes = minutes % 10

    return '{:02}:{:02}'.format(hours, minutes)

