        for j in range(i, n + 1):
            b[i][j] = int(s[i - 1] * s[j - 1]) if i != j else int(s[i - 1] ** 2
                                                                  if i > 1 else int(s[i - 1].isdigit() and s[i - 1])

    result = 0
    for i in range(1, n + 1):
        for j in range(i, n + 1):
            for x in range(i, j + 1):
                for y in range(i, j):
                    if sum(b[x][y + 1:j + 1]) == a:
