import sys

def get_ways(people, boat_weight):
    if sum(people) > boat_weight:
        return 0
    if len(people) == 1:
        return 1
    ways = 0
    for i in range(len(people)):
        new_people = people[:i] + people[i+1:]
        ways += get_ways(new_people, boat_weight)
    return ways

def get_min_rides(people, boat_weight):
    if sum(people) > boat_weight:
        return -1
    if len(people) == 1:
        return 1
    min_rides = sys.maxint
    for i in range(len(people)):
        new_people = people[:i] + people[i+1:]
        new_rides = get_min_rides(new_people, boat_weight)
        if new_rides != -1:
            min_rides = min(min_rides, new_rides + 1)
    return min_rides

def main():
    n, k = map(int, raw_input().split())
    people = map(int, raw_input().split())
    print get_min_rides(people, k)
    print get_ways(people, k) % 1000000007

if __name__ == '__main__':
    main()

import math

def prime_factors(n):
    factors = set()
    while n % 2 == 0:
        factors.add(2),
        n = n / 2
    for i in range(3,int(math.sqrt(n))+1,2):
        while n % i== 0:
            factors.add(int(i))
            n = n / i
    if n > 2:
        factors.add(int(n))
    return factors

