def find_swap_positions(s, t):
    i = 0
    while s and s[0] == t[0]:
        i += 1
        s = s[1:]

    a_count = 0
    b_count = 0
    for char in s:
        if char == 'a':
            a_count += 1
        else:
            b_count += 1

    if a_count > 0 and b_count > 0:
        return i, 0

    if not s:
        return i, len(t)

    if a_count > 0:
        return i, len(t) - (len(t) - b_count)

    return i + 1, len(t)

s = input()
