import sys

def is_possible(N, P, X):
    # Check if the total weight of vertices with the same color as v is less than or equal to X
    for i in range(N):
        if P[i] == i:
            continue
        weight = 0
        for j in range(i+1, N):
            if P[j] == i:
                weight += X[j]
        if weight > X[i]:
            return False
    return True

