import java.util.Scanner;

public class Solution {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int n = scanner.nextInt();
        int d = scanner.nextInt();
        int k = scanner.nextInt();

        if (constructTree(n, d, k)) {
            System.out.println("YES");
            printTree(n);
        } else {
            System.out.println("NO");
        }
    }

    public static boolean constructTree(int n, int d, int k) {
        // construct a tree with n vertices, diameter at most d, and degree of each vertex at most k
        // return true if a tree can be constructed, false otherwise
        int[][] adjacencyList = new int[n][n];
        boolean[] visited = new boolean[n];

        // start at a random vertex and explore the tree
        int start = (int) (n * Math.random());
        visited[start] = true;
        adjacencyList[start] = new int[n];

        // explore the tree by recursively traversing the adjacency list
        for (int i = 0; i < n; i++) {
            int neighbor = adjacencyList[start][i];
            if (neighbor != -1) {
                // if a neighbor exists, explore it
                if (!visited[neighbor]) {
                    // if the neighbor is not visited, explore it
                    constructTree(n, d, k);
                    return false; // cannot construct a tree with diameter at most d and degree of each vertex at most k
                }
            }
        }

        // if we reach this point, a tree can be constructed
        return true;
    }

    public static void printTree(int n) {
        // print the edges of the tree in a breadth-first manner
        for (int i = 0; i < n - 1; i++) {
            System.out.print(i + " ");
            for (int j = 0; j < n; j++) {
                if (adjacencyList[i][j] != -1) {
                    System.out.print(j + " ");
                }
            }
            System.out.println();
        }
    }
}

