def balance_string(s):
    n = len(s)
    count_0 = s.count('0')
    count_1 = s.count('1')
    count_2 = n - count_0 - count_1

    if count_0 > count_1:
        min_char = '1'
        max_char = '0'
    else:
        min_char = '0'
        max_char = '1'

    result = []
    for char in s:
        if char == min_char:
            result.append(min_char)
        elif char == max_char:
            result.append(min_char)
        else:
            result.append(char)

    while len(result) < n:
        result.append(min_char)

    return ''.join(result)


