def max_increasing_subarray_length(n, a):
    if n == 1:
        return 0
    dp = [1] * n
    for i in range(1, n):
        for j in range(i):
            if a[i] > a[j]:
                dp[i] = max(dp[i], dp[j] + 1)
    return max(dp)

