def find_string(s, m, b):
    # Create a list to store the indices of letters in s
    indices = {char: i for i, char in enumerate(s)}

    # Create a set to store the letters in t
    letters = set()

    # Try all possible combinations of letters in t
    for subset in powerset(indices.keys()):
        t = [s[i] for i in sorted(list(indices.keys()) if i in subset)]
        if len(t) == m:
            # Calculate the array b for the current combination of letters in t
            b_calc = [0] * m
            for i in range(m):
                for j in range(m):
                    if i != j and t[i] < t[j] and (j not in subset):
                        b_calc[i] += abs(i - j)
            # Check if the calculated array b matches the given array b
            if b_calc == b:
                return ''.join(t)

# Helper function to generate all subsets of a given list
def powerset(lst):
    return [set(lst) for lst in itertools.chain([[]], (itertools.combinations(lst, r) for r in range(1, len(lst)+1)))]

