def count_median_pairs(n, m, p):
    count = 0
    for l in range(1, n+1):
        for r in range(l, n+1):
            subsequence = p[l-1:r]
            subsequence.sort()
            if len(subsequence) % 2 == 0:
                median = subsequence[len(subsequence)//2 - 1]
            else:
                median = subsequence[len(subsequence)//2]
            if median == m:
                count += 1
    return count

