def evaluate_expression(expression):
    result = 0
    operator = '+'
    num = ''

    for char in expression:
        if char.isdigit():
            num += char
        else:
            if operator == '+':
                result -= int(num)
            elif operator == '-':
                result += int(num)
            operator = char
            num = ''

    if operator == '+':
        result -= int(num)
    elif operator == '-':
        result += int(num)

    return result

expression = input().strip()
print(evaluate_expression(expression))

