def is_achievable(N, M, X, books):
    min_cost = float('inf')

    for i in range(1 << N):
        understanding_levels = [0] * M
        cost = 0

        for j in range(N):
            if (i >> j) & 1:
                cost += books[j][0]
                for k in range(M):
                    understanding_levels[k] += books[j][1][k]

        if all(level >= X for level in understanding_levels):
            min_cost = min(min_cost, cost)

    if min_cost == float('inf'):
        return "Impossible"
    else:
        return min_cost

