def is_palindrome(s):
 return s == s[::-1]

def min_hugs(s):
 left, right = 0, len(s) - 1
 while left < right:
 if s[left] != s[right]:
 # Find the character to be changed
 char_to_change = None
 min_pos = len(s)
 for i in range(len(s)):
 if s[i] != s[left] and abs(i - left) < abs(min_pos - left):
 min_pos = i
 # Change the character and check if the string is palindromic
 s = s[:min_pos] + s[min_pos+1:] + s[min_pos:min_pos+1] + s[:min_pos]
 if is_palindrome(s):
 return left + 1
 left += 1
 return -1

