def dfs(graph, start, visited):
    visited.append(start)
    for i in graph[start]:
        if i not in visited:
            dfs(graph, i, visited)
    return visited


def bfs(graph, start, visited):
    queue = [start]
    visited.append(start)
    while queue:
        vertex = queue.pop(0)
        for i in graph[vertex]:
            if i not in visited:
                queue.append(i)
                visited.append(i)
    return visited


