from collections import defaultdict

N, M = map(int, input().split())

cities = defaultdict(list)
for i in range(M):
    P, Y = map(int, input().split())
    cities[P].append((Y, i+1))

for k in cities.keys():
    cities[k].sort()

result = []
for k in cities.keys():
    for i, (Y, idx) in enumerate(cities[k]):
        city_id = str(k).zfill(6) + str(i+1).zfill(6)
        result.append((idx, city_id))

result.sort()
for idx, city_id in result:
    print(city_id)
